<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const salario=parseFloat(document.getElementById('fgts-salario').value);clearError();if(isNaN(salario)||salario<=0){showError('Informe um salário bruto válido maior que zero.');return;}const mensal=salario*0.08;document.getElementById('fgts-valor').textContent='R$ '+fmtBRL(mensal);document.getElementById('fgts-anual').textContent='R$ '+fmtBRL(mensal*12);document.getElementById('tool-detail').textContent='Cálculo com alíquota padrão de 8% sobre o salário bruto.';showResult('tool-result');}function clearTool(){document.getElementById('fgts-salario').value='';['fgts-valor','fgts-anual'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o FGTS antes de copiar o resultado.');return;}copyToClipboard('FGTS mensal: '+document.getElementById('fgts-valor').textContent+'\nFGTS anual: '+document.getElementById('fgts-anual').textContent,button);}
</script>
